mapper.select:
SELECT u.id, u.username, u.nickname, u.avatar, u.email, u.phone, u.gender, u.status, u.dept_id, u.create_time, d.dept_name FROM sys_user u LEFT JOIN sys_dept d ON u.dept_id = d.id WHERE u.del_flag = '0'
AND u.dept_id = #{deptId}
AND u.username LIKE CONCAT('%', #{username}, '%')
AND u.phone LIKE CONCAT('%', #{phone}, '%')
AND u.status = #{status}
${dataScope}
ORDER BY u.create_time DESC

